final:
module gray_code_counter(
	input clk,
	input reset,
	output reg [2:0] gray_code);

reg [2:0] invalid_gray;

always @(posedge clk) begin
	if (reset)
		invalid_gray <= 3'b000;
	else
		invalid_gray <= invalid_gray + 1;
end

always @(invalid_gray) begin
	gray_code = invalid_gray ^ (invalid_gray >> 1);
end

endmodule
